import React, { useState } from "react";
import Header from "../components/Header";
import BackHomeButton from "../components/BackHomeButton";

export default function AddTransaction() {
  <BackHomeButton />;
  // State for form inputs
  const [name, setName] = useState("");
  const [amount, setAmount] = useState("");
  const [interest, setInterest] = useState("");
  const [date, setDate] = useState("");
  const [modeOfPayment, setModeOfPayment] = useState("");
  const [givenOrTaken, setGivenOrTaken] = useState("Given");
  const [file, setFile] = useState(null);

  const handleSubmit = (e) => {
    e.preventDefault();
    // Implement API submission here
    alert("Transaction added (connect to backend)");
  };

  return (
    <div style={{ background: "#F3F6FC", minHeight: "100vh" }}>
      <Header />
      <div style={{ maxWidth: 600, margin: "0 auto", padding: "2rem 1rem" }}>
        <h2
          style={{
            color: "#5D5FEF",
            fontWeight: 700,
            fontSize: 24,
            marginBottom: 18,
          }}
        >
          Add Transaction
        </h2>
        <form
          onSubmit={handleSubmit}
          style={{
            background: "#fff",
            borderRadius: 14,
            padding: "2rem",
            boxShadow: "0 2px 8px #7286D122",
          }}
        >
          <div style={{ marginBottom: 14 }}>
            <input
              type="text"
              placeholder="Name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              required
              style={inputStyle}
            />
          </div>
          <div style={{ marginBottom: 14 }}>
            <input
              type="number"
              placeholder="Amount"
              value={amount}
              onChange={(e) => setAmount(e.target.value)}
              required
              style={inputStyle}
            />
          </div>
          <div style={{ marginBottom: 14 }}>
            <input
              type="text"
              placeholder="Interest Rate (%)"
              value={interest}
              onChange={(e) => setInterest(e.target.value)}
              required
              style={inputStyle}
            />
          </div>
          <div style={{ marginBottom: 14 }}>
            <input
              type="date"
              value={date}
              onChange={(e) => setDate(e.target.value)}
              required
              style={inputStyle}
            />
          </div>
          <div style={{ marginBottom: 14 }}>
            <input
              type="text"
              placeholder="Mode of Payment"
              value={modeOfPayment}
              onChange={(e) => setModeOfPayment(e.target.value)}
              style={inputStyle}
            />
          </div>
          <div style={{ marginBottom: 14 }}>
            <select
              value={givenOrTaken}
              onChange={(e) => setGivenOrTaken(e.target.value)}
              style={inputStyle}
            >
              <option value="Given">Given</option>
              <option value="Taken">Taken</option>
            </select>
          </div>
          <div style={{ marginBottom: 20 }}>
            <input type="file" onChange={(e) => setFile(e.target.files[0])} />
          </div>
          <button
            type="submit"
            style={{
              background: "#5D5FEF",
              color: "#fff",
              borderRadius: 12,
              border: 0,
              padding: "10px 28px",
              fontWeight: 600,
              fontSize: 16,
              cursor: "pointer",
            }}
          >
            Add
          </button>
        </form>
      </div>
    </div>
  );
}

const inputStyle = {
  width: "100%",
  padding: "10px 14px",
  borderRadius: 8,
  border: "1px solid #D1D8ED",
  fontSize: 16,
  boxSizing: "border-box",
};
